     1→//! Favor encoding - Firemark and Coronet identity types
     2→//!
     3→//! Implements base64 encoding/decoding for Job Jockey identity types:
     4→//! - Firemark: Heat identity (2 base64 chars, 0-4095)
     5→//! - Coronet: Pace identity (5 base64 chars, globally unique)
     6→
     7→use serde::{Deserialize, Serialize};
     8→
     9→/// URL-safe base64 charset (RFC 4648 section 5)
    10→pub const CHARSET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
    11→
    12→/// Firemark prefix character
    13→pub const FIREMARK_PREFIX: char = '₣';
    14→
    15→/// Coronet prefix character
    16→pub const CORONET_PREFIX: char = '₢';
    17→
    18→/// Maximum value for Firemark (2^12 - 1)
    19→pub const FIREMARK_MAX: u16 = 4095;
    20→
    21→/// Maximum value for Coronet pace index (2^18 - 1)
    22→pub const CORONET_PACE_MAX: u32 = 262143;
    23→
    24→/// Look up the position of a character in the charset
    25→fn char_to_value(c: char) -> Result<u8, String> {
    26→    let byte = c as u8;
    27→    CHARSET
    28→        .iter()
    29→        .position(|&b| b == byte)
    30→        .map(|pos| pos as u8)
    31→        .ok_or_else(|| format!("Invalid base64 character: '{}'", c))
    32→}
    33→
    34→/// Get the character at a given position in the charset
    35→fn value_to_char(value: u8) -> char {
    36→    CHARSET[value as usize] as char
    37→}
    38→
    39→/// Heat identity - 2 base64 characters encoding 0-4095
    40→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    41→pub struct Firemark(String);
    42→
    43→/// Pace identity - 5 base64 characters, globally unique
    44→/// First 2 chars encode parent Heat, last 3 encode pace index (0-262143)
    45→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    46→pub struct Coronet(String);
    47→
    48→impl Firemark {
    49→    /// Encode an integer (0-4095) as a Firemark
    50→    pub fn encode(value: u16) -> Self {
    51→        debug_assert!(value <= FIREMARK_MAX, "Firemark value {} exceeds max {}", value, FIREMARK_MAX);
    52→        let high = value_to_char((value / 64) as u8);
    53→        let low = value_to_char((value % 64) as u8);
    54→        Firemark(format!("{}{}", high, low))
    55→    }
    56→
    57→    /// Decode a Firemark to its integer value
    58→    pub fn decode(&self) -> Result<u16, String> {
    59→        let chars: Vec<char> = self.0.chars().collect();
    60→        if chars.len() != 2 {
    61→            return Err(format!("Firemark must be 2 characters, got {}", chars.len()));
    62→        }
    63→        let high = char_to_value(chars[0])? as u16;
    64→        let low = char_to_value(chars[1])? as u16;
    65→        Ok(high * 64 + low)
    66→    }
    67→
    68→    /// Parse a Firemark from string input (with or without prefix)
    69→    pub fn parse(input: &str) -> Result<Self, String> {
    70→        let stripped = input.strip_prefix(FIREMARK_PREFIX).unwrap_or(input);
    71→        if stripped.len() != 2 {
    72→            return Err(format!(
    73→                "Firemark must be 2 base64 characters (with or without {} prefix), got '{}'",
    74→                FIREMARK_PREFIX, input
    75→            ));
    76→        }
    77→        // Validate all characters are in charset
    78→        for c in stripped.chars() {
    79→            char_to_value(c)?;
    80→        }
    81→        Ok(Firemark(stripped.to_string()))
    82→    }
    83→
    84→    /// Get the raw base64 string (without prefix)
    85→    pub fn as_str(&self) -> &str {
    86→        &self.0
    87→    }
    88→
    89→    /// Format with prefix for display
    90→    pub fn display(&self) -> String {
    91→        format!("{}{}", FIREMARK_PREFIX, self.0)
    92→    }
    93→}
    94→
    95→impl Coronet {
    96→    /// Encode a Heat identity and pace index as a Coronet
    97→    pub fn encode(heat: &Firemark, pace_index: u32) -> Self {
    98→        debug_assert!(
    99→            pace_index <= CORONET_PACE_MAX,
   100→            "Coronet pace index {} exceeds max {}",
   101→            pace_index,
   102→            CORONET_PACE_MAX
   103→        );
   104→        let p2 = value_to_char((pace_index / 4096) as u8);
   105→        let p1 = value_to_char(((pace_index / 64) % 64) as u8);
   106→        let p0 = value_to_char((pace_index % 64) as u8);
   107→        Coronet(format!("{}{}{}{}", heat.as_str(), p2, p1, p0))
   108→    }
   109→
   110→    /// Decode a Coronet to its parent Heat and pace index
   111→    pub fn decode(&self) -> Result<(Firemark, u32), String> {
   112→        let chars: Vec<char> = self.0.chars().collect();
   113→        if chars.len() != 5 {
   114→            return Err(format!("Coronet must be 5 characters, got {}", chars.len()));
   115→        }
   116→        let heat = Firemark(chars[0..2].iter().collect());
   117→        let p2 = char_to_value(chars[2])? as u32;
   118→        let p1 = char_to_value(chars[3])? as u32;
   119→        let p0 = char_to_value(chars[4])? as u32;
   120→        let pace_index = p2 * 4096 + p1 * 64 + p0;
   121→        Ok((heat, pace_index))
   122→    }
   123→
   124→    /// Parse a Coronet from string input (with or without prefix)
   125→    pub fn parse(input: &str) -> Result<Self, String> {
   126→        let stripped = input.strip_prefix(CORONET_PREFIX).unwrap_or(input);
   127→        if stripped.len() != 5 {
   128→            return Err(format!(
   129→                "Coronet must be 5 base64 characters (with or without {} prefix), got '{}'",
   130→                CORONET_PREFIX, input
   131→            ));
   132→        }
   133→        // Validate all characters are in charset
   134→        for c in stripped.chars() {
   135→            char_to_value(c)?;
   136→        }
   137→        Ok(Coronet(stripped.to_string()))
   138→    }
   139→
   140→    /// Get the raw base64 string (without prefix)
   141→    pub fn as_str(&self) -> &str {
   142→        &self.0
   143→    }
   144→
   145→    /// Format with prefix for display
   146→    pub fn display(&self) -> String {
   147→        format!("{}{}", CORONET_PREFIX, self.0)
   148→    }
   149→
   150→    /// Extract the parent Firemark (first 2 base64 chars)
   151→    pub fn parent_firemark(&self) -> Firemark {
   152→        Firemark(self.0[..2].to_string())
   153→    }
   154→}
   155→
   156→#[cfg(test)]
   157→mod tests {
   158→    use super::*;
   159→
   160→    #[test]
   161→    fn test_charset_length() {
   162→        assert_eq!(CHARSET.len(), 64);
   163→    }
   164→
   165→    #[test]
   166→    fn test_charset_values() {
   167→        // Verify specific positions in charset
   168→        assert_eq!(char_to_value('A').unwrap(), 0);
   169→        assert_eq!(char_to_value('B').unwrap(), 1);
   170→        assert_eq!(char_to_value('Z').unwrap(), 25);
   171→        assert_eq!(char_to_value('a').unwrap(), 26);
   172→        assert_eq!(char_to_value('z').unwrap(), 51);
   173→        assert_eq!(char_to_value('0').unwrap(), 52);
   174→        assert_eq!(char_to_value('9').unwrap(), 61);
   175→        assert_eq!(char_to_value('-').unwrap(), 62);
   176→        assert_eq!(char_to_value('_').unwrap(), 63);
   177→    }
   178→
   179→    #[test]
   180→    fn test_char_to_value_invalid() {
   181→        assert!(char_to_value('!').is_err());
   182→        assert!(char_to_value(' ').is_err());
   183→        assert!(char_to_value('+').is_err());
   184→        assert!(char_to_value('/').is_err());
   185→    }
   186→
   187→    // Firemark tests
   188→
   189→    #[test]
   190→    fn test_firemark_encode_zero() {
   191→        let fm = Firemark::encode(0);
   192→        assert_eq!(fm.as_str(), "AA");
   193→        assert_eq!(fm.display(), "₣AA");
   194→    }
   195→
   196→    #[test]
   197→    fn test_firemark_encode_one() {
   198→        let fm = Firemark::encode(1);
   199→        assert_eq!(fm.as_str(), "AB");
   200→        assert_eq!(fm.display(), "₣AB");
   201→    }
   202→
   203→    #[test]
   204→    fn test_firemark_encode_64() {
   205→        // 64 = 1*64 + 0
   206→        let fm = Firemark::encode(64);
   207→        assert_eq!(fm.as_str(), "BA");
   208→    }
   209→
   210→    #[test]
   211→    fn test_firemark_encode_max() {
   212→        // 4095 = 63*64 + 63
   213→        let fm = Firemark::encode(4095);
   214→        assert_eq!(fm.as_str(), "__");
   215→        assert_eq!(fm.display(), "₣__");
   216→    }
   217→
   218→    #[test]
   219→    fn test_firemark_encode_decode_roundtrip() {
   220→        for value in [0, 1, 63, 64, 65, 100, 1000, 4000, 4095] {
   221→            let fm = Firemark::encode(value);
   222→            let decoded = fm.decode().unwrap();
   223→            assert_eq!(decoded, value, "Roundtrip failed for {}", value);
   224→        }
   225→    }
   226→
   227→    #[test]
   228→    fn test_firemark_decode_invalid_length() {
   229→        let fm = Firemark("A".to_string());
   230→        assert!(fm.decode().is_err());
   231→
   232→        let fm = Firemark("ABC".to_string());
   233→        assert!(fm.decode().is_err());
   234→    }
   235→
   236→    #[test]
   237→    fn test_firemark_parse_with_prefix() {
   238→        let fm = Firemark::parse("₣AB").unwrap();
   239→        assert_eq!(fm.as_str(), "AB");
   240→        assert_eq!(fm.decode().unwrap(), 1);
   241→    }
   242→
   243→    #[test]
   244→    fn test_firemark_parse_without_prefix() {
   245→        let fm = Firemark::parse("AB").unwrap();
   246→        assert_eq!(fm.as_str(), "AB");
   247→        assert_eq!(fm.decode().unwrap(), 1);
   248→    }
   249→
   250→    #[test]
   251→    fn test_firemark_parse_invalid() {
   252→        assert!(Firemark::parse("A").is_err());
   253→        assert!(Firemark::parse("ABC").is_err());
   254→        assert!(Firemark::parse("₣A").is_err());
   255→        assert!(Firemark::parse("₣ABC").is_err());
   256→        assert!(Firemark::parse("A!").is_err());
   257→    }
   258→
   259→    // Coronet tests
   260→
   261→    #[test]
   262→    fn test_coronet_encode_zero() {
   263→        let heat = Firemark::encode(0);
   264→        let coronet = Coronet::encode(&heat, 0);
   265→        assert_eq!(coronet.as_str(), "AAAAA");
   266→        assert_eq!(coronet.display(), "₢AAAAA");
   267→    }
   268→
   269→    #[test]
   270→    fn test_coronet_encode_one() {
   271→        let heat = Firemark::encode(0);
   272→        let coronet = Coronet::encode(&heat, 1);
   273→        assert_eq!(coronet.as_str(), "AAAAB");
   274→    }
   275→
   276→    #[test]
   277→    fn test_coronet_encode_64() {
   278→        // pace 64 = 0*4096 + 1*64 + 0
   279→        let heat = Firemark::encode(0);
   280→        let coronet = Coronet::encode(&heat, 64);
   281→        assert_eq!(coronet.as_str(), "AAABA");
   282→    }
   283→
   284→    #[test]
   285→    fn test_coronet_encode_4096() {
   286→        // pace 4096 = 1*4096 + 0*64 + 0
   287→        let heat = Firemark::encode(0);
   288→        let coronet = Coronet::encode(&heat, 4096);
   289→        assert_eq!(coronet.as_str(), "AABAA");
   290→    }
   291→
   292→    #[test]
   293→    fn test_coronet_encode_max_pace() {
   294→        // 262143 = 63*4096 + 63*64 + 63
   295→        let heat = Firemark::encode(0);
   296→        let coronet = Coronet::encode(&heat, 262143);
   297→        assert_eq!(coronet.as_str(), "AA___");
   298→    }
   299→
   300→    #[test]
   301→    fn test_coronet_encode_with_nonzero_heat() {
   302→        let heat = Firemark::encode(1); // "AB"
   303→        let coronet = Coronet::encode(&heat, 0);
   304→        assert_eq!(coronet.as_str(), "ABAAA");
   305→        assert_eq!(coronet.display(), "₢ABAAA");
   306→    }
   307→
   308→    #[test]
   309→    fn test_coronet_decode_roundtrip() {
   310→        for heat_val in [0, 1, 100, 4095] {
   311→            for pace_val in [0, 1, 63, 64, 4096, 100000, 262143] {
   312→                let heat = Firemark::encode(heat_val);
   313→                let coronet = Coronet::encode(&heat, pace_val);
   314→                let (decoded_heat, decoded_pace) = coronet.decode().unwrap();
   315→                assert_eq!(
   316→                    decoded_heat.decode().unwrap(),
   317→                    heat_val,
   318→                    "Heat roundtrip failed for heat={} pace={}",
   319→                    heat_val,
   320→                    pace_val
   321→                );
   322→                assert_eq!(
   323→                    decoded_pace, pace_val,
   324→                    "Pace roundtrip failed for heat={} pace={}",
   325→                    heat_val, pace_val
   326→                );
   327→            }
   328→        }
   329→    }
   330→
   331→    #[test]
   332→    fn test_coronet_parent_firemark() {
   333→        let heat = Firemark::encode(42);
   334→        let coronet = Coronet::encode(&heat, 123);
   335→        let parent = coronet.parent_firemark();
   336→        assert_eq!(parent.as_str(), heat.as_str());
