//! JJK CLI subcommands for vvx
//!
//! Implements jjx_* subcommands that delegate to JJK library functions.
//! This module is only compiled when the jjk feature is enabled.

use clap::Args;
use std::path::PathBuf;

/// Arguments for jjx_validate subcommand
#[derive(Args, Debug)]
pub struct ValidateArgs {
    /// Path to the Gallops JSON file
    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    pub file: PathBuf,
}

/// Run the jjx_validate subcommand
pub fn run_validate(args: ValidateArgs) -> i32 {
    // Load the Gallops file
    let gallops = match jjk::jjrg_gallops::Gallops::load(&args.file) {
        Ok(g) => g,
        Err(e) => {
            eprintln!("Error loading Gallops: {}", e);
            return 1;
        }
    };

    // Validate the structure
    match gallops.validate() {
        Ok(()) => {
            println!("Gallops validation passed");
            0
        }
        Err(errors) => {
            eprintln!("Gallops validation failed with {} error(s):", errors.len());
            for error in errors {
                eprintln!("  - {}", error);
            }
            1
        }
    }
}

